uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv2;
float ang2, c, s;
vUv -= 0.5;
vUv *= uAspect.xy;
float dist = 1;
float inten = 1;
ret1 = 0;
int anz = 3;
float n = 0;
while (n <= anz) {
    dist = 1-fract(n/anz)/anz;
    inten =  sqrt(dist);
    vec2 uv3 =  fract(vUv*dist);
    uv3 = .5 + (uv3-.5)*vec2(1,1.5);;
    neu = GetPixel (uv3) -.2*GetBlur3 (uv3*1.5);
    neu = lum(neu)*vec3 (.9,.9,1.2)+neu;
    ret1 = max(ret1,neu*inten);
    n++;
}
//ret1 = mix(.5*ret1,ret1*(GetBlur1(vUv)),pow(hue_shader,ret1));
//ret1 *= 1.5;

vec3 hue = vec3 (-hue_shader.z,hue_shader.xy);
vec3 ret_hue;
ret_hue.x = clamp01((ret1.x-0.5)*hue.x + 0.5);
ret_hue.y = clamp01((ret1.y-0.5)*hue.y + 0.5);
ret_hue.z = clamp01((ret1.z-0.5)*hue.z + 0.5);
ret = ret_hue;
ret += .5;
ret *= 1-.1*vRadius*length(ret1);
ret *= 1-vUv.y/2-.2*roam_cos;

  fragColor = ret;
}
